import React from 'react';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const navigate = useNavigate();

    const handleLogin = (e) => {
        e.preventDefault();
        // Simulate login
        navigate('/');
    };

    return (
        <div className="page-container p-6">
            <h1 className="text-2xl font-bold mb-4">Login</h1>
            <form onSubmit={handleLogin} className="max-w-md space-y-4">
                <div>
                    <label className="block mb-1">Email</label>
                    <input type="email" required className="w-full border p-2 rounded" />
                </div>
                <div>
                    <label className="block mb-1">Password</label>
                    <input type="password" required className="w-full border p-2 rounded" />
                </div>
                <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">Sign In</button>
            </form>
        </div>
    );
};

export default Login;
